"use client";

import { FormEvent, useState } from "react";
import { useRouter } from "next/navigation";
import { Box, Button, Card, CardContent, Stack, TextField, Typography } from "@mui/material";

import { FeedbackState } from "@/components/ui/feedback-state";
import { login } from "@/services/auth";

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState("owner@example.com");
  const [password, setPassword] = useState("change-me-please");
  const [state, setState] = useState<"idle" | "loading" | "error" | "success">("idle");
  const [message, setMessage] = useState<string>("");

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setState("loading");
    try {
      await login(email, password);
      setState("success");
      setMessage("Signed in successfully.");
      router.push("/years/2026");
      router.refresh();
    } catch (error) {
      const reason = error instanceof Error ? error.message : "Unable to sign in";
      setState("error");
      setMessage(reason);
    }
  }

  return (
    <Box sx={{ minHeight: "100dvh", display: "grid", placeItems: "center", px: 2 }}>
      <Card sx={{ width: "100%", maxWidth: 460 }}>
        <CardContent>
          <form onSubmit={handleSubmit}>
            <Stack spacing={2}>
              <Typography variant="h4">Welcome back</Typography>
              <Typography color="text.secondary">Sign in to manage annual household expenses.</Typography>
              <TextField
                id="email"
                label="Email"
                type="email"
                value={email}
                onChange={(event) => setEmail(event.target.value)}
                required
              />
              <TextField
                id="password"
                label="Password"
                type="password"
                value={password}
                onChange={(event) => setPassword(event.target.value)}
                required
              />
              <Button type="submit" variant="contained">
                Sign in
              </Button>
              <FeedbackState state={state} message={message} />
            </Stack>
          </form>
        </CardContent>
      </Card>
    </Box>
  );
}
